import { useState, useEffect } from "react";
import API from "../services/api";
import { supabase } from "../services/supabaseClient";

export default function Upload({ user, setUser }) {
  const [file, setFile] = useState(null);
  const [text, setText] = useState("");
  const [summary, setSummary] = useState("");
  const [showSummary, setShowSummary] = useState(false);
  const [loading, setLoading] = useState(false);

  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [asking, setAsking] = useState(false);

  const [docId, setDocId] = useState(null);
  const [userId, setUserId] = useState(null);

  const [papers, setPapers] = useState([]);

  // 💡 IDEAS STATE
  const [ideas, setIdeas] = useState([]);
  const [keywords, setKeywords] = useState([]);
  const [domain, setDomain] = useState("");
  const [subdomain, setSubdomain] = useState("");

  // 🔥 AUTO TRIGGER
  const [autoRunIdeas, setAutoRunIdeas] = useState(false);

  // 🔐 Auth Header
  const getAuthHeader = async () => {
    const { data: { session } } = await supabase.auth.getSession();
    return session ? { Authorization: `Bearer ${session.access_token}` } : {};
  };

  // 📄 Upload
  const handleUpload = async () => {
    if (!file) return alert("Select a file");

    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const formData = new FormData();
      formData.append("file", file);

      const res = await API.post("/upload", formData, {
        headers: {
          ...authHeader,
          "Content-Type": "multipart/form-data"
        }
      });

      setText(res.data.preview);
      setDocId(res.data.doc_id);
      setUserId(res.data.user_id);

      // reset states
      setAnswer("");
      setQuestion("");
      setSummary("");
      setShowSummary(false);
      setPapers([]);
      setIdeas([]);
      setKeywords([]);
      setDomain("");
      setSubdomain("");

    } catch (err) {
      console.error(err);
      alert("Upload failed ❌");
    } finally {
      setLoading(false);
    }
  };

  // 💬 Q&A
  const askQuestion = async () => {
    if (!question || !docId) return alert("Upload + enter question");

    try {
      setAsking(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/ask", {
        question,
        doc_id: docId,
        user_id: userId
      }, { headers: authHeader });

      setAnswer(res.data.answer);

    } catch (err) {
      console.error(err);
    } finally {
      setAsking(false);
    }
  };

  // 🧠 Summary
  const handleGenerateSummary = async () => {
    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/summarize", { text }, { headers: authHeader });

      setSummary(res.data.summary);
      setShowSummary(true);

    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // 🔍 Recommendations
  const handleRecommend = async () => {
    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/recommend", {
        query: text
      }, { headers: authHeader });

      setPapers(res.data.recommendations || []);

    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // 💡 IDEAS
  const handleIdeas = async () => {
    try {
      const authHeader = await getAuthHeader();

      const res = await API.post("/ideas", { text }, { headers: authHeader });

      setIdeas(res.data.ideas);
      setKeywords(res.data.keywords);
      setDomain(res.data.domain);
      setSubdomain(res.data.subdomain || "");

    } catch (err) {
      console.error(err);
      alert("Failed to generate ideas ❌");
    }
  };

  // 🔥 CHECK LOCALSTORAGE TRIGGER
  useEffect(() => {
    if (localStorage.getItem("runIdeas") === "true") {
      setAutoRunIdeas(true);
      localStorage.removeItem("runIdeas");
    }
  }, []);

  // 🔥 AUTO RUN AFTER UPLOAD
  useEffect(() => {
    if (autoRunIdeas && text) {
      handleIdeas();
      setAutoRunIdeas(false);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [autoRunIdeas, text]);

  return (
    <div id="upload-section" className="space-y-8">

      {/* Upload Card */}
      <div className="bg-white/90 dark:bg-deepnavy-light/90 p-8 rounded-2xl shadow-lg shadow-sapphire/5 border border-babyblue/10 dark:border-babyblue/10">
        <div className="flex items-center gap-3 mb-6">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-sapphire to-cornflower flex items-center justify-center text-lg shadow-md shadow-sapphire/20">📄</div>
          <div>
            <h2 className="text-xl font-bold text-sapphire dark:text-babyblue">Upload Research Paper</h2>
            <p className="text-sm text-sapphire/50 dark:text-periwinkle/50">Supported format: PDF</p>
          </div>
        </div>

        <div className="flex gap-4 items-center">
          <label className="flex-1 flex items-center gap-3 px-5 py-4 rounded-xl bg-periwinkle/20 dark:bg-deepnavy/40 border-2 border-dashed border-babyblue/30 dark:border-babyblue/20 cursor-pointer hover:border-sapphire/50 hover:bg-periwinkle/30 transition-all group">
            <span className="text-2xl group-hover:scale-110 transition-transform">📎</span>
            <span className="text-sm text-sapphire/60 dark:text-periwinkle/60 truncate">
              {file ? file.name : "Click to select a PDF file"}
            </span>
            <input
              type="file"
              accept=".pdf"
              onChange={(e) => setFile(e.target.files[0])}
              className="hidden"
            />
          </label>

          <button onClick={handleUpload} className="btn shadow-lg shadow-sapphire/20">
            {loading ? "Processing..." : "Upload"}
          </button>
        </div>
      </div>

      {/* Preview */}
      {text && (
        <div className="bg-white/80 dark:bg-deepnavy-light/80 backdrop-blur-sm p-6 rounded-2xl border border-babyblue/10 dark:border-babyblue/10 shadow-md">
          <div className="flex items-center gap-2 mb-3">
            <span className="w-2 h-2 rounded-full bg-cornflower"></span>
            <h3 className="font-bold text-sapphire dark:text-babyblue text-sm uppercase tracking-wider">Preview</h3>
          </div>
          <p className="text-sapphire/60 dark:text-periwinkle/70 leading-relaxed">{text.slice(0, 500)}...</p>
        </div>
      )}

      {/* Actions */}
      {text && (
        <div className="flex gap-3 flex-wrap">
          <button onClick={handleGenerateSummary} className="btn shadow-lg shadow-sapphire/20">🧠 Summary</button>
          <button onClick={handleRecommend} className="btn shadow-lg shadow-sapphire/20">🔍 Recommend</button>
          <button onClick={handleIdeas} className="btn shadow-lg shadow-sapphire/20">💡 Ideas</button>
        </div>
      )}

      {/* Summary */}
      {showSummary && (
        <div className="bg-gradient-to-br from-periwinkle/40 to-babyblue/20 dark:from-deepnavy/60 dark:to-sapphire/10 p-6 rounded-2xl border border-babyblue/20 dark:border-babyblue/10 shadow-md">
          <div className="flex items-center gap-2 mb-3">
            <span className="w-2 h-2 rounded-full bg-sapphire"></span>
            <h3 className="font-bold text-sapphire dark:text-babyblue text-sm uppercase tracking-wider">Summary</h3>
          </div>
          <p className="text-sapphire/70 dark:text-periwinkle/80 leading-relaxed">{summary}</p>
        </div>
      )}

      {/* Q&A */}
      {text && (
        <div className="bg-white/80 dark:bg-deepnavy-light/80 backdrop-blur-sm p-6 rounded-2xl border border-babyblue/10 dark:border-babyblue/10 shadow-md">
          <div className="flex items-center gap-2 mb-4">
            <span className="w-2 h-2 rounded-full bg-cornflower"></span>
            <h3 className="font-bold text-sapphire dark:text-babyblue text-sm uppercase tracking-wider">Ask a Question</h3>
          </div>

          <div className="flex gap-3">
            <input
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              className="flex-1 border p-3.5 rounded-xl dark:bg-deepnavy/40 dark:text-babyblue dark:border-babyblue/20 border-babyblue/20 focus:outline-none focus:ring-2 focus:ring-sapphire/30 transition-all"
              placeholder="What is the main contribution of this paper?"
              onKeyDown={(e) => e.key === 'Enter' && askQuestion()}
            />
            <button onClick={askQuestion} className="btn shadow-lg shadow-sapphire/20">
              {asking ? "Thinking..." : "Ask"}
            </button>
          </div>

          {answer && (
            <div className="mt-4 p-4 rounded-xl bg-periwinkle/20 dark:bg-babyblue/5 border border-babyblue/10">
              <p className="text-sapphire/70 dark:text-periwinkle/80 leading-relaxed">{answer}</p>
            </div>
          )}
        </div>
      )}

      {/* Recommendations */}
      {papers.length > 0 && (
        <div className="bg-white/80 dark:bg-deepnavy-light/80 backdrop-blur-sm p-6 rounded-2xl border border-babyblue/10 dark:border-babyblue/10 shadow-md">
          <div className="flex items-center gap-2 mb-4">
            <span className="w-2 h-2 rounded-full bg-cornflower"></span>
            <h3 className="font-bold text-sapphire dark:text-babyblue text-sm uppercase tracking-wider">Related Papers</h3>
          </div>
          <div className="space-y-2">
            {papers.map((p, i) => (
              <div key={i} className="p-3 rounded-lg bg-periwinkle/20 dark:bg-babyblue/5 text-sapphire/70 dark:text-periwinkle/70 text-sm">
                {p}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Domain + Keywords */}
      {domain && (
        <div className="bg-gradient-to-r from-periwinkle/50 to-babyblue/30 dark:from-deepnavy/60 dark:to-sapphire/10 p-6 rounded-2xl border border-babyblue/20 dark:border-babyblue/10 shadow-md">
          <div className="flex items-center gap-2 mb-3">
            <span className="w-2 h-2 rounded-full bg-sapphire"></span>
            <h3 className="text-lg font-semibold text-sapphire dark:text-babyblue">
              🧠 Domain: {domain}
            </h3>
          </div>

          {subdomain && (
            <p className="text-sm text-sapphire/60 dark:text-periwinkle/60 mb-4">
              Subdomain: {subdomain}
            </p>
          )}

          <div className="flex gap-2 flex-wrap">
            {keywords.map((k, i) => (
              <span
                key={i}
                className="bg-white/70 dark:bg-sapphire/20 text-sapphire dark:text-babyblue px-4 py-1.5 rounded-full text-xs font-semibold shadow-sm"
              >
                {k}
              </span>
            ))}
          </div>
        </div>
      )}

      {/* Ideas */}
      {ideas.length > 0 && (
        <div>
          <div className="flex items-center gap-2 mb-4">
            <span className="w-2 h-2 rounded-full bg-cornflower"></span>
            <h3 className="font-bold text-sapphire dark:text-babyblue text-sm uppercase tracking-wider">Generated Ideas</h3>
          </div>
          <div className="grid md:grid-cols-2 gap-4">
            {ideas.map((idea, i) => (
              <div key={i} className="bg-white/90 dark:bg-deepnavy-light/90 p-5 rounded-2xl shadow-md shadow-sapphire/5 border border-babyblue/10 dark:border-babyblue/10 hover:shadow-lg hover:shadow-sapphire/10 transition-all duration-300 hover:-translate-y-1">
                <h3 className="font-bold text-sapphire dark:text-babyblue mb-2">{idea.title}</h3>
                <p className="text-sm text-sapphire/60 dark:text-periwinkle/70 mb-3">{idea.description}</p>
                <p className="text-xs text-sapphire/40 dark:text-periwinkle/50 mb-3">💡 {idea.use_case}</p>

                <ul className="text-xs text-sapphire/50 dark:text-periwinkle/60 list-disc ml-4 mb-3 space-y-1">
                  {idea.reasons?.map((r, idx) => (
                    <li key={idx}>{r}</li>
                  ))}
                </ul>

                <div className="flex justify-between items-center pt-3 border-t border-babyblue/10 dark:border-babyblue/10">
                  <span className="text-xs font-medium text-cornflower bg-cornflower/10 px-2 py-1 rounded-md">{idea.category}</span>
                  <span className="text-xs font-bold text-sapphire dark:text-babyblue">Score: {idea.score}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

    </div>
  );
}
